// Robust to n8n auto-split of array response
let t = $input.first().json;
if (Array.isArray(t)) t = t[0];
if (!t || !t.slug_en) {
  throw new Error('No topic from Supabase: ' + JSON.stringify(t).slice(0,200));
}

// Generate slug_ru by transliterating title_ru
function tr(s) {
  const m = {'а':'a','б':'b','в':'v','г':'g','д':'d','е':'e','ё':'yo','ж':'zh','з':'z','и':'i','й':'y','к':'k','л':'l','м':'m','н':'n','о':'o','п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'kh','ц':'ts','ч':'ch','ш':'sh','щ':'sch','ъ':'','ы':'y','ь':'','э':'e','ю':'yu','я':'ya'};
  return (s||'').toLowerCase().split('').map(c => m[c] !== undefined ? m[c] : c).join('').replace(/[^a-z0-9-]/g,'-').replace(/-+/g,'-').replace(/^-|-$/g,'').slice(0,80);
}
const slugRu = tr(t.title_ru);
const slugEn = t.slug_en;

const BLOG_BASE = $env.BLOG_BASE_URL || 'https://example.com/blog';
const ruUrl = BLOG_BASE + '/' + slugRu + '/';
const enUrl = BLOG_BASE + '/' + slugEn + '/';

const AUTHOR_NAME = $env.AUTHOR_NAME || 'Author';
const AUTHOR_URL = $env.AUTHOR_URL || 'https://example.com';
const AUTHOR_BIO = $env.AUTHOR_BIO || 'AI architect.';

const prompt = `You are ${AUTHOR_NAME}. ${AUTHOR_BIO}

Write TWO expert articles on the SAME topic — one in Russian, one in English.

RU title: "${t.title_ru}"
EN title: "${t.title_en}"

Requirements for EACH version:
- 900-1200 words
- Structure: opening hook (2-3 paragraphs) → 3-5 H2 sections with H3 subsections where useful → FAQ block with 4-5 Q&A formatted as <h3>Question?</h3><p>Answer</p> → conclusion with CTA
- Style: expert, first-person, concrete code examples, numbers, tool names
- Avoid marketing fluff (no "game-changer", "revolutionize", "disrupt", "unlock")
- Use <ul>/<ol> bullets, <pre><code class=\"language-xxx\"> code blocks, <table> when comparing
- Prepend each article HTML with a JSON-LD Schema.org Article block: <script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"Article\",\"headline\":\"...\",\"author\":{\"@type\":\"Person\",\"name\":\"${AUTHOR_NAME}\",\"url\":\"${AUTHOR_URL}\"},\"datePublished\":\"${new Date().toISOString().split('T')[0]}\",\"inLanguage\":\"...\"}</script>

Output STRICTLY in this format:

===RU===
TITLE: <Russian title without quotes>
CONTENT:
<HTML body in Russian>

===EN===
TITLE: <English title without quotes>
CONTENT:
<HTML body in English>`;

return [{ json: {
  topic_id: t.id,
  prompt,
  slug_ru: slugRu,
  slug_en: slugEn,
  title_ru: t.title_ru,
  title_en: t.title_en,
  ru_url: ruUrl,
  en_url: enUrl,
  has_video: false,
  video_slug: null,
  hype_score: t.hype_score,
  date: new Date().toISOString().split('T')[0]
}}];

const raw = $input.first().json.choices?.[0]?.message?.content || '';
const prep = $('Prepare Prompts + URLs').first().json;

// split by ===RU=== / ===EN===
const ruMatch = raw.match(/===RU===([\s\S]*?)===EN===/);
const enMatch = raw.match(/===EN===([\s\S]*)$/);

function extract(block){
  if (!block) return {title:null, html:null};
  const tm = block.match(/TITLE:\s*(.+?)\n/);
  const cm = block.match(/CONTENT:\s*([\s\S]+)/);
  return {
    title: tm ? tm[1].trim() : null,
    html: cm ? cm[1].trim() : null,
  };
}

const ru = extract(ruMatch ? ruMatch[1] : null);
const en = extract(enMatch ? enMatch[1] : null);

if (!ru.title || !ru.html || !en.title || !en.html) {
  throw new Error('Failed to parse bilingual response. Raw: ' + raw.substring(0, 500));
}

// prepend hreflang <link> tags into each HTML for AEO cross-language signal
const hreflangRu = `<link rel="alternate" hreflang="ru" href="${prep.ru_url}" /><link rel="alternate" hreflang="en" href="${prep.en_url}" /><link rel="alternate" hreflang="x-default" href="${prep.en_url}" />`;

return [{ json: {
  title_ru: ru.title,
  html_ru: hreflangRu + ru.html,
  slug_ru: prep.slug_ru,
  title_en: en.title,
  html_en: hreflangRu + en.html,
  slug_en: prep.slug_en,
  ru_url: prep.ru_url,
  en_url: prep.en_url,
  has_video: prep.has_video,
  video_slug: prep.video_slug,
  date: prep.date,
}}];

// Pure JS Ghost JWT — no require('crypto') needed (n8n sandbox compatible)
// Reads keyId and keySecret from env: GHOST_ADMIN_KEY = "<keyId>:<keySecret>"
const K=[0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
function rr(n,x){return(x>>>n)|(x<<(32-n));}
function sha256(bytes){let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;const l=bytes.length;const bl=l*8;const pad=new Uint8Array(((l+9+63)&~63));pad.set(bytes);pad[l]=0x80;const dv=new DataView(pad.buffer);dv.setUint32(pad.length-4,bl,false);for(let off=0;off<pad.length;off+=64){const w=new Int32Array(64);for(let i=0;i<16;i++)w[i]=dv.getInt32(off+i*4,false);for(let i=16;i<64;i++){const s0=(rr(7,w[i-15])^rr(18,w[i-15])^(w[i-15]>>>3));const s1=(rr(17,w[i-2])^rr(19,w[i-2])^(w[i-2]>>>10));w[i]=(w[i-16]+s0+w[i-7]+s1)|0;}let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;for(let i=0;i<64;i++){const S1=rr(6,e)^rr(11,e)^rr(25,e);const ch=(e&f)^(~e&g);const t1=(h+S1+ch+K[i]+w[i])|0;const S0=rr(2,a)^rr(13,a)^rr(22,a);const maj=(a&b)^(a&c)^(b&c);const t2=(S0+maj)|0;h=g;g=f;f=e;e=(d+t1)|0;d=c;c=b;b=a;a=(t1+t2)|0;}h0=(h0+a)|0;h1=(h1+b)|0;h2=(h2+c)|0;h3=(h3+d)|0;h4=(h4+e)|0;h5=(h5+f)|0;h6=(h6+g)|0;h7=(h7+h)|0;}const r=new Uint8Array(32);const rv=new DataView(r.buffer);rv.setUint32(0,h0);rv.setUint32(4,h1);rv.setUint32(8,h2);rv.setUint32(12,h3);rv.setUint32(16,h4);rv.setUint32(20,h5);rv.setUint32(24,h6);rv.setUint32(28,h7);return r;}
function hmacSha256(key,msg){if(key.length>64){key=sha256(key);}const k=new Uint8Array(64);k.set(key);const ip=new Uint8Array(64);const op=new Uint8Array(64);for(let i=0;i<64;i++){ip[i]=k[i]^0x36;op[i]=k[i]^0x5c;}const inner=new Uint8Array(64+msg.length);inner.set(ip);inner.set(msg,64);const ih=sha256(inner);const outer=new Uint8Array(64+32);outer.set(op);outer.set(ih,64);return sha256(outer);}
function b64url(buf){return Buffer.from(buf).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');}
const ghostAdminKey = $env.GHOST_ADMIN_KEY || '';
if (!ghostAdminKey.includes(':')) throw new Error('GHOST_ADMIN_KEY env must be in format <keyId>:<keySecret>');
const [keyId, keySecret] = ghostAdminKey.split(':');
const now=Math.floor(Date.now()/1000);
const header=b64url(JSON.stringify({alg:'HS256',typ:'JWT',kid:keyId}));
const payload=b64url(JSON.stringify({iat:now,exp:now+300,aud:'/admin/'}));
const sigInput=new TextEncoder().encode(header+'.'+payload);
const keyBytes=Uint8Array.from(keySecret.match(/.{2}/g).map(b=>parseInt(b,16)));
const sig=b64url(hmacSha256(keyBytes,sigInput));
const item=$input.first().json;
return [{json:{...item, ghost_jwt: header+'.'+payload+'.'+sig}}];

const d = $('Build Ghost JWT').first().json;
const post = `${d.title_en}

Just published a new deep-dive on the blog.

What's inside:
• Concrete architecture patterns you can ship tomorrow
• Real code examples
• FAQ with common questions

Read the full article -> ${d.en_url}

What's your take? Comment below.

#AI #EnterpriseAI #ClaudeCode #Automation #B2B #MachineLearning`;
return [{json:{...d, linkedin_text: post}}];

